  "warranty": "<section class=\"section\" id=\"warranty\">\r\n  <div class=\"container split-grid\">\r\n    <div class=\"reveal\">\r\n      <h2 class=\"section-title\">Chính sách hậu mãi rõ ràng</h2>\r\n      <ul class=\"bullet-list\">\r\n        <li>Bảo hành 12 tháng</li>\r\n        <li>Lỗi đổi mới theo chính sách</li>\r\n        <li>Hỗ trợ kỹ thuật trọn đời</li>\r\n        <li>Quản lý bảo hành qua App VRTECH Connect</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <div class=\"warranty-image-card reveal\">\r\n      <img\r\n        src=\"images/products12thv2/all/baohanh12th.webp\"\r\n        alt=\"Chính sách bảo hành 12 tháng cho Carlinkit TBox V2 by VRTECH\"\r\n        width=\"617\"\r\n        height=\"337\"\r\n        loading=\"lazy\"\r\n      >\r\n    </div>\r\n  </div>\r\n</section>",
